SELECT supplier_name, address, email
FROM suppliers
WHERE supplier_id < 20;

SELECT supplier_id, supplier_name
FROM suppliers
WHERE updated_at = (SELECT MAX(updated_at) FROM suppliers);

SELECT supplier_name
FROM suppliers
WHERE updated_at = (SELECT MAX(updated_at) FROM suppliers);

SELECT supplier_name
FROM suppliers
ORDER BY supplier_name ASC;

SELECT COUNT(*)
FROM suppliers
WHERE address = 'A specific location' AND email IS NOT NULL;

SELECT 
    (SELECT supplier_name FROM suppliers ORDER BY updated_at DESC LIMIT 1) AS most_recent_supplier,
    (SELECT supplier_name FROM suppliers ORDER BY updated_at ASC LIMIT 1) AS least_recent_supplier;

SELECT supplier_name
FROM suppliers
WHERE LENGTH(phone_number) = (
  SELECT MIN(LENGTH(phone_number))
  FROM suppliers
);

SELECT supplier_name, updated_at
FROM suppliers
WHERE updated_at = (SELECT MAX(updated_at) FROM suppliers);

SELECT supplier_name, email 
FROM suppliers 
WHERE email LIKE '%@example.com';

SELECT supplier_name, 
       DENSE_RANK() OVER (ORDER BY IFNULL(updated_at, '1900-01-01') DESC) as rank
FROM suppliers;
